-- Ajoute HT/TVA a la conso + recharge tous les mois (HT/TVA par carte).
alter table public.total_conso add column if not exists total_ht  numeric;
alter table public.total_conso add column if not exists total_tva numeric;

on conflict (id) do update set
  total_ht = excluded.total_ht, total_tva = excluded.total_tva, total_ttc = excluded.total_ttc,
  carburant_ttc = excluded.carburant_ttc, litres = excluded.litres, boutique_ttc = excluded.boutique_ttc,
  lavage_ttc = excluded.lavage_ttc, peage_ttc = excluded.peage_ttc;